export declare const ruleOperands: readonly ["lt", "lte", "eq", "neq", "gt", "gte", "exists", "nexists", "contains", "ncontains", "isyes", "isno"];
export type TRuleOperand = typeof ruleOperands[number];
export interface IRule {
    left: string;
    operand: TRuleOperand;
    right: string;
}
export interface ICondition {
    type: "rule" | "condition";
    condition: string;
    rule: IRule;
}
